    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizationService
{
    // Common English stop words excluded from scoring
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "from", "as",
        "into", "through", "during", "before", "after", "it", "its",
        "this", "that", "these", "those", "he", "she", "they", "we", "you",
        "i", "me", "him", "her", "us", "them", "my", "your", "his",
        "our", "their", "be", "been", "being", "have", "has", "had",
        "do", "does", "did", "will", "would", "shall", "should", "may",
        "might", "can", "could", "not", "no", "so", "if", "then", "than",
        "too", "very", "just", "about", "also", "which", "who", "whom",
        "what", "when", "where", "how", "all", "each", "every", "both",
        "few", "more", "most", "other", "some", "such", "only", "own",
        "same", "up", "out", "there", "here"
    };

    /// <summary>
    /// Produces an extractive summary by scoring sentences based on word frequency
    /// and returning the top-ranked sentences in their original order.
    /// </summary>
    public string Summarize(string documentText, int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scored = ScoreSentences(sentences, wordFrequencies);

        // Pick top sentences, then restore original order
        var topIndices = scored
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .Select(s => s.Index)
            .Order()
            .ToList();

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    private static List<string> SplitIntoSentences(string text)
    {
        // Split on sentence-ending punctuation followed by whitespace or end of string
        var raw = SentenceBoundary().Split(text);
        return raw
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in ExtractWords(sentence))
            {
                if (!StopWords.Contains(word) && word.Length > 1)
                {
                    freq[word] = freq.TryGetValue(word, out var count) ? count + 1 : 1;
                }
            }
        }

        return freq;
    }

    private static List<(int Index, double Score)> ScoreSentences(
        List<string> sentences, Dictionary<string, int> wordFrequencies)
    {
        var maxFreq = wordFrequencies.Count > 0 ? wordFrequencies.Values.Max() : 1;

        return sentences.Select((sentence, index) =>
        {
            var words = ExtractWords(sentence);
            if (words.Count == 0)
                return (index, Score: 0.0);

            double score = words
                .Where(w => wordFrequencies.ContainsKey(w))
                .Sum(w => (double)wordFrequencies[w] / maxFreq);

            // Normalize by word count to avoid bias toward long sentences
            score /= words.Count;

            return (index, Score: score);
        }).ToList();
    }

    private static List<string> ExtractWords(string text)
    {
        return WordPattern().Matches(text)
            .Select(m => m.Value.ToLowerInvariant())
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+")]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\b[a-zA-Z]+\b")]
    private static partial Regex WordPattern();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _summarizer;

    public SummarizeController(DocumentSummarizationService summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = _summarizer.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

